const SOPS = {
  'SOP-01': { nom: 'Qualification initiale alarme', objectif: 'Identifier et qualifier l\'alarme dans Lightsoft + Vizee, évaluer l\'impact opérationnel, horodater l\'incident.' },
  'SOP-02': { nom: 'Vérification rack OOB', objectif: 'Contrôler l\'infrastructure OOB : alimentation, switch, firewall Vizee, câblage, caméra, Lugos.' },
  'SOP-03': { nom: 'Vérification supervision Lightsoft', objectif: 'Vérifier la session Lightsoft et l\'accessibilité des NEs via Radius/STMS.' },
  'SOP-04': { nom: 'Vérification bascule OLP + OSNR', objectif: 'Tester la bascule OLP et contrôler les niveaux OSNR sur les 2 ports optiques.' },
  'SOP-05': { nom: 'Vérification physique rack OTN', objectif: 'Vérification physique sur site : voyants cartes, alimentation, ventilation, identification par photo.' },
  'SOP-06': { nom: 'Vérification carte RCP', objectif: 'Basculer la carte RCP A\u2192B et vérifier câblage cuivre + état File System.' },
  'SOP-07': { nom: 'Vérification port SFP + jarretière', objectif: 'Inspecter le port SFP et la jarretière optique : état, propreté, alignement, côté opérateur.' },
  'SOP-08': { nom: 'Ouverture ticket opérateur', objectif: 'Ouvrir un ticket auprès de l\'opérateur tiers (Cogent, EuNetwork) et suivre la résolution.' },
  'SOP-09': { nom: 'Ouverture ticket Lugos', objectif: 'Ouvrir un ticket Lugos pour intervention OOB ou câblage terrain.' },
  'SOP-10': { nom: 'Ouverture ticket Ribbon + RMA', objectif: 'Ouvrir un ticket Ribbon avec numéro de série (Vizee) et initier le processus RMA.' },
  'SOP-11': { nom: 'Communication incident', objectif: 'Informer sites, manager, Ribbon ; envoyer mail d\'incident et mails de suivi toutes les 30 min jusqu\'à clôture.' },
  'SOP-12': { nom: 'Lecture PM Counters Lightsoft', objectif: 'Lire les PM Counters Lightsoft (OPR/OPT, FEC, BER) pour analyse qualité de lien.' },
  'SOP-13': { nom: 'Validation post-résolution — Test Viavi OTU2 (RFC 2544)', objectif: 'Valider la conformité du lien restauré par test RFC 2544 (2 Viavi OTU2) aux 2 extrémités.' },
};

const PHASE_MAP = {
  'SOP-01': 1,
  'SOP-02': 2, 'SOP-03': 2, 'SOP-04': 2, 'SOP-05': 2, 'SOP-06': 2, 'SOP-07': 2, 'SOP-12': 2,
  'SOP-08': 3, 'SOP-09': 3, 'SOP-10': 3,
  'SOP-11': 4,
  'SOP-13': 5,
};

const PHASES = {
  1: { nom: 'Qualification', description: 'Qualifier l\'alarme, évaluer l\'impact opérationnel et horodater l\'incident pour initialiser le traitement.' },
  2: { nom: 'Diagnostic & Intervention', description: 'Identifier la cause racine par des vérifications techniques ciblées sur les équipements concernés.' },
  3: { nom: 'Escalade / RMA', description: 'Ouvrir les tickets opérateur/constructeur et initier le processus RMA si remplacement matériel nécessaire.' },
  4: { nom: 'Communication', description: 'Informer toutes les parties prenantes (sites, manager, constructeur) et assurer le suivi jusqu\'à clôture.' },
  5: { nom: 'Validation', description: 'Valider la conformité du lien restauré par test RFC 2544 (Viavi OTU2) avant remise en service définitive.' },
};

const body = $input.first().json.body || $input.first().json;
const { incident_id, incident_type, sous_type, criticite, sops, site, equipment, technicien, date_intervention, heure_debut } = body;

const sopsArr = typeof sops === 'string' ? sops.split(',').map(s => s.trim()).filter(Boolean) : (sops || []);

const phaseGroups = {};
for (const s of sopsArr) {
  const ph = PHASE_MAP[s] || 2;
  if (!phaseGroups[ph]) phaseGroups[ph] = [];
  phaseGroups[ph].push(s);
}

const phaseNums = Object.keys(phaseGroups).map(Number).sort();
let phasesHtml = '';
for (const phNum of phaseNums) {
  const ph = PHASES[phNum] || { nom: 'Phase ' + phNum, description: '' };
  const phSops = phaseGroups[phNum];
  const sopRows = phSops.map(s => {
    const info = SOPS[s] || { nom: s, objectif: '' };
    return '<tr><td class="sop-id">' + s + '</td><td class="sop-nom">' + info.nom + '</td><td>' + info.objectif + '</td><td class="checkbox">\u2610</td></tr>';
  }).join('\n');
  phasesHtml += '<div class="phase-block">'
    + '<div class="phase-header"><span class="phase-num">Phase ' + phNum + '</span><span class="phase-nom"> \u2014 ' + ph.nom + '</span></div>'
    + '<div class="phase-desc">' + ph.description + '</div>'
    + '<table class="sop-table"><thead><tr><th>SOP</th><th>Proc\u00e9dure</th><th>Objectif dans ce MOP</th><th>Val.</th></tr></thead>'
    + '<tbody>' + sopRows + '</tbody></table>'
    + '</div>';
}

const criticiteClass = { MINEUR: 'crit-mineur', MAJEUR: 'crit-majeur', CRITIQUE: 'crit-critique' }[criticite] || '';
const dateStr = date_intervention || new Date().toISOString().slice(0, 10);
const heureStr = heure_debut || '--:--';
const genTime = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';
const filename = 'mop-' + incident_id + '.pdf';
const docxFilename = 'mop-' + incident_id + '.docx';

const html = '<!DOCTYPE html>\n<html lang="fr">\n<head>\n<meta charset="UTF-8">\n<style>\n'
  + '* { box-sizing: border-box; margin: 0; padding: 0; }\n'
  + 'body { font-family: Arial, Helvetica, sans-serif; font-size: 10.5pt; color: #222; background: #fff; padding: 18mm 20mm; }\n'
  + 'h1 { font-size: 17pt; color: #0d2b52; border-bottom: 3px solid #0d2b52; padding-bottom: 6px; margin-bottom: 14px; }\n'
  + '.meta-block { background: #f0f5fb; border-left: 4px solid #0d2b52; padding: 10px 14px; margin-bottom: 18px; border-radius: 2px; }\n'
  + '.meta-grid { display: grid; grid-template-columns: 130px 1fr 130px 1fr; gap: 4px 8px; }\n'
  + '.meta-label { font-weight: bold; color: #555; font-size: 9.5pt; }\n'
  + '.crit-mineur { color: #2e7d32; font-weight: bold; }\n'
  + '.crit-majeur { color: #e65100; font-weight: bold; }\n'
  + '.crit-critique { color: #b71c1c; font-weight: bold; background: #fff3f3; padding: 1px 4px; border-radius: 2px; }\n'
  + '.phase-block { margin-bottom: 20px; border: 1px solid #d0d8e8; border-radius: 3px; overflow: hidden; }\n'
  + '.phase-header { background: #0d2b52; color: #fff; padding: 7px 12px; font-size: 10.5pt; }\n'
  + '.phase-num { font-weight: bold; }\n'
  + '.phase-desc { background: #f7f9fc; padding: 7px 12px; font-size: 9.5pt; color: #555; border-bottom: 1px solid #d0d8e8; font-style: italic; }\n'
  + 'table.sop-table { width: 100%; border-collapse: collapse; }\n'
  + 'table.sop-table th { background: #3a5a8a; color: #fff; padding: 6px 10px; text-align: left; font-size: 9.5pt; }\n'
  + 'table.sop-table td { padding: 6px 10px; border-bottom: 1px solid #dde4ef; vertical-align: top; font-size: 9.5pt; }\n'
  + 'table.sop-table tr:nth-child(even) td { background: #f7f9fc; }\n'
  + '.sop-id { font-weight: bold; color: #0d2b52; white-space: nowrap; width: 70px; }\n'
  + '.sop-nom { width: 200px; font-weight: 500; }\n'
  + '.checkbox { text-align: center; width: 50px; font-size: 13pt; color: #888; }\n'
  + '.sig-block { margin-top: 26px; display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 16px; }\n'
  + '.sig-box { border: 1px solid #bbb; padding: 8px 12px; min-height: 55px; border-radius: 2px; }\n'
  + '.sig-label { font-size: 9pt; color: #777; margin-bottom: 4px; }\n'
  + '.footer { margin-top: 20px; font-size: 8.5pt; color: #aaa; border-top: 1px solid #ddd; padding-top: 6px; text-align: right; }\n'
  + '</style>\n</head>\n<body>\n'
  + '<h1>MOP \u2014 M\u00e9thode d\'Op\u00e9ration et de Proc\u00e9dure</h1>\n'
  + '<div class="meta-block"><div class="meta-grid">'
  + '<span class="meta-label">Incident ID</span><span>' + (incident_id || 'N/A') + '</span>'
  + '<span class="meta-label">Site</span><span>' + (site || 'N/A') + '</span>'
  + '<span class="meta-label">Cat\u00e9gorie</span><span>' + (incident_type || 'N/A') + '</span>'
  + '<span class="meta-label">Composant</span><span>' + (sous_type || equipment || 'N/A') + '</span>'
  + '<span class="meta-label">Criticit\u00e9</span><span><span class="' + criticiteClass + '">' + (criticite || 'N/A') + '</span></span>'
  + '<span class="meta-label">Technicien</span><span>' + (technicien || 'N/A') + '</span>'
  + '<span class="meta-label">Date</span><span>' + dateStr + '</span>'
  + '<span class="meta-label">Heure d\u00e9but</span><span>' + heureStr + '</span>'
  + '</div></div>\n'
  + '<h2 style="font-size:11pt;color:#0d2b52;margin:0 0 12px;text-transform:uppercase;letter-spacing:0.3px;">'
  + 'Proc\u00e9dures applicables \u2014 ' + sopsArr.length + ' SOP(s) en ' + phaseNums.length + ' phase(s)</h2>\n'
  + phasesHtml
  + '\n<div class="sig-block">'
  + '<div class="sig-box"><div class="sig-label">Technicien intervenant</div></div>'
  + '<div class="sig-box"><div class="sig-label">Responsable NOC</div></div>'
  + '<div class="sig-box"><div class="sig-label">Cl\u00f4ture \u2014 heure fin</div></div>'
  + '</div>'
  + '\n<div class="footer">G\u00e9n\u00e9r\u00e9 automatiquement par MOP Machinery \u2014 ' + genTime + '</div>'
  + '\n</body>\n</html>';

const buf = Buffer.from(html, 'utf8');
return [{
  json: { incident_id, filename, docxFilename, html },
  binary: {
    'index.html': {
      data: buf.toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];
